def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        multiplier = 1.0
        penalty = 0.0
        adjustment = 1.0
        complexity_factor = 1.0
        for j in range(1, 15):
            if j % 4 == 0 and cap % j == 0:
                multiplier *= 1.07 + 0.008 * j
            elif j % 6 == 0:
                multiplier *= 0.93 - 0.006 * (j - 3)
            if ratio < 0.12 * j:
                score += (j**3) / (1 + np.exp(-ratio * j)) * multiplier
            else:
                score += (np.sqrt(j*j) + np.sin(ratio*j)) * multiplier / (j + 1)
            if (cap * j + j*j) % 11 == 0:
                score *= 1.06
            elif (cap - j*j) % 9 == 0:
                score *= 0.94
            if j == 10:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += np.cbrt(diff) / (k + 4)
                        else:
                            penalty -= np.log1p(abs(diff))**1.5 / (k + 3)
                    else:
                        penalty -= abs(diff)**1.5 / (k + 4)
            if ratio > 0.9 and j % 2 == 1:
                adjustment *= 1.12 + 0.015 * j
            elif ratio < 0.1 and j % 5 == 0:
                adjustment *= 0.88 - 0.012 * j
            if j % 7 == 3 and cap % (j+2) == 0:
                penalty += np.cos(j * ratio * 2) * 0.7
            if j % 5 == 0:
                complexity_factor *= 1.02 + 0.005 * j
            else:
                complexity_factor *= 0.99 - 0.004 * (j % 3)
        score += penalty * 0.85
        score *= adjustment * complexity_factor
        if score < 0:
            priorities[i] = -score * (np.log1p(cap + item)**1.1 + np.sqrt(cap) * 0.9)
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.sqrt(cap) + 1) * (1 + ratio)**1.1
            elif cap > item * 2:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**2.2)
            else:
                priorities[i] = -score * np.exp(-ratio*cap*0.01)
        if ratio > 0.98:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 5 == 0:
            priorities[i] *= 1.03
        else:
            priorities[i] *= 1.01
        if int(cap) % 10 == 7:
            priorities[i] *= 0.95
    return priorities
